import requests

def get_billboard_hot100_artist(artist_name):
    url = f'https://api.billboard.com/api/v1/chart/hot-100/songs?artist_name={artist_name}'
    response = requests.get(url)
    if response.status_code == 200:
        data = response.json()
        for song in data['data']:
            print(f"Song: {song['title']}, Peak Position: {song['peak_position']}")
    else:
        print('Failed to fetch data')

get_billboard_hot100_artist('070 Shake')
